'use client';

import { motion } from 'framer-motion';
import { gsap } from '@/lib/animations/gsap';
import { ScrollTrigger } from 'gsap/ScrollTrigger';
import { useRef, useEffect } from 'react';
import Image from 'next/image';
import { Button } from '@/components/ui/button';
import { Card } from '@/components/ui/card';
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription } from '@/components/ui/dialog';
import { useGlobalStore } from '@/lib/store/useGlobalStore';

const projects = [
  {
    id: '1',
    title: 'E-Commerce Platform',
    description: 'Full-featured online store with cart, checkout, and payment integration.',
    techStack: ['Next.js', 'Stripe', 'PostgreSQL', 'Prisma'],
    image: '/images/project1.jpg',
    liveUrl: 'https://example.com',
    githubUrl: 'https://github.com/example',
  },
  {
    id: '2',
    title: 'AI Content Generator',
    description: 'Web app that generates marketing content using OpenAI API.',
    techStack: ['React', 'Node.js', 'OpenAI', 'Tailwind'],
    image: '/images/project2.jpg',
    liveUrl: 'https://example.com',
    githubUrl: 'https://github.com/example',
  },
  {
    id: '3',
    title: 'Task Management Dashboard',
    description: 'Real-time collaborative task manager with drag-and-drop interface.',
    techStack: ['Next.js', 'Socket.io', 'MongoDB', 'Framer Motion'],
    image: '/images/project3.jpg',
    liveUrl: 'https://example.com',
    githubUrl: 'https://github.com/example',
  },
];

export default function Projects() {
  const sectionRef = useRef<HTMLDivElement>(null);
  const { selectedProject, setSelectedProject, isProjectModalOpen, toggleProjectModal } = useGlobalStore();

  useEffect(() => {
    if (!sectionRef.current) return;
    gsap.fromTo(
      sectionRef.current.querySelectorAll('.project-card'),
      { y: 80, opacity: 0 },
      {
        y: 0,
        opacity: 1,
        stagger: 0.2,
        duration: 1,
        scrollTrigger: { trigger: sectionRef.current, start: 'top 75%' },
      }
    );
  }, []);

  return (
    <section id="projects" ref={sectionRef} className="py-20 md:py-32 bg-secondary/30">
      <div className="container mx-auto px-4">
        <motion.h2 initial={{ opacity: 0 }} whileInView={{ opacity: 1 }} className="text-3xl md:text-4xl font-bold text-center mb-12 gradient-text">
          Featured Projects
        </motion.h2>
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
          {projects.map((project) => (
            <Card key={project.id} className="project-card overflow-hidden glass group">
              <div className="relative h-48 w-full">
                <Image src={project.image} alt={project.title} fill className="object-cover group-hover:scale-105 transition-transform duration-300" />
              </div>
              <div className="p-6">
                <h3 className="text-xl font-semibold mb-2">{project.title}</h3>
                <p className="text-muted-foreground mb-4">{project.description}</p>
                <div className="flex flex-wrap gap-2 mb-4">
                  {project.techStack.map((tech) => (
                    <span key={tech} className="px-3 py-1 text-sm bg-primary/10 text-primary rounded-full">
                      {tech}
                    </span>
                  ))}
                </div>
                <div className="flex gap-4">
                  <Button variant="outline" size="sm" onClick={() => { setSelectedProject(project); toggleProjectModal(); }}>
                    View Details
                  </Button>
                  {project.liveUrl && (
                    <Button size="sm" asChild>
                      <a href={project.liveUrl} target="_blank" rel="noopener noreferrer">Live Demo</a>
                    </Button>
                  )}
                </div>
              </div>
            </Card>
          ))}
        </div>
      </div>

      <Dialog open={isProjectModalOpen} onOpenChange={toggleProjectModal}>
        <DialogContent className="max-w-2xl">
          <DialogHeader>
            <DialogTitle>{selectedProject?.title}</DialogTitle>
            <DialogDescription>{selectedProject?.description}</DialogDescription>
          </DialogHeader>
          {selectedProject && (
            <div className="space-y-4">
              <div className="relative h-64 w-full rounded-lg overflow-hidden">
                <Image src={selectedProject.image} alt={selectedProject.title} fill className="object-cover" />
              </div>
              <div className="flex flex-wrap gap-2">
                {selectedProject.techStack.map((tech) => (
                  <span key={tech} className="px-3 py-1 text-sm bg-primary/10 text-primary rounded-full">
                    {tech}
                  </span>
                ))}
              </div>
              <div className="flex gap-4">
                {selectedProject.liveUrl && (
                  <Button asChild>
                    <a href={selectedProject.liveUrl} target="_blank" rel="noopener noreferrer">Live Demo</a>
                  </Button>
                )}
                {selectedProject.githubUrl && (
                  <Button variant="outline" asChild>
                    <a href={selectedProject.githubUrl} target="_blank" rel="noopener noreferrer">Source Code</a>
                  </Button>
                )}
              </div>
            </div>
          )}
        </DialogContent>
      </Dialog>
    </section>
  );
}
